import math
from dataclasses import dataclass


@dataclass(frozen=True)
class RiskLimits:
    max_risk_per_trade_pct: float = 1.0


def size_position(capital, entry_price, stop_price, risk_pct=None, limits=None):
    """Calculate long position size for a fixed loss budget."""
    limits = limits or RiskLimits()
    risk_pct = limits.max_risk_per_trade_pct if risk_pct is None else risk_pct
    try:
        capital_f = float(capital)
        entry_f = float(entry_price)
        stop_f = float(stop_price)
        risk_pct_f = float(risk_pct)
    except (TypeError, ValueError):
        return 0
    if (
        not all(math.isfinite(value) for value in (capital_f, entry_f, stop_f, risk_pct_f))
        or min(capital_f, entry_f, stop_f, risk_pct_f) <= 0
    ):
        return 0
    risk_amount = capital_f * (risk_pct_f / 100.0)
    risk_per_share = entry_f - stop_f
    if risk_per_share <= 0:
        return 0
    shares = int(risk_amount / risk_per_share)
    max_by_notional = int((capital_f * 0.20) / entry_f)
    return max(0, min(shares, max_by_notional))

