from dataclasses import dataclass


def normalize_direction(value):
    return "short" if str(value or "").strip().lower() == "short" else "long"


@dataclass(frozen=True)
class SizingSignal:
    ticker: str
    direction: str
    entry_price: float
    stop_price: float
    quantity: int
